import subprocess
import os

def generate_requirements_txt_with_hashes():
    """
    Generates a requirements.txt file with hashes for all dependencies.
    
    Usage:
        python manage_dependencies.py generate-requirements-txt-with-hashes
    
    This function runs pip-compile to create a requirements.txt file that includes SHA256 hashes for each dependency.
    """
    subprocess.run(["pip", "install", "pip-tools"])
    subprocess.run(["pip-compile", "--output-file=requirements.txt"])

